  function wEmojis(){return WORLD_DATA[world%WORLD_DATA.length].em;}
  const SPW_BASE=1.30,SPW_STEP=0.20,SPW_BAND=25;
  // Build-cost base. Raised 160->384 (x2.4) to slow village build-out: a 1200
  // spin pack now clears ~5 worlds instead of ~12. Tune this single number to
  // adjust pacing (higher = slower progress, more grind/monetization pressure).
  const BUILD_BASE=384;
  function worldCostMult(){return SPW_BASE*Math.pow(1+SPW_STEP,Math.floor(world/SPW_BAND));}
  function buildCost(){return Math.round(BUILD_BASE*Math.pow(ECON_BASE,totBuild)*buildMult()*worldCostMult());}
  function villageSum(){return village.reduce((a,b)=>a+b,0);}
  function worldItems(){return WORLD_ITEMS[world%WORLD_ITEMS.length];}
  function itemCost(i){return Math.round(buildCost()*(1+0.18*village[i]));}
  function stars(n){let s='';for(let i=0;i<STARS;i++)s+=(i<n?'★':'☆');return s;}
  function maxedWorld(){return villageSum()>=ITEMS*STARS;}
  function econScale(){return Math.pow(ECON_BASE,totBuild);}
  function bonus(x){return Math.round(x*econScale());}
  function payMult(){return econScale()*(specialWorld?2:1)*(frenzy>0?FRENZY_MULT:1);}
  function pigCap(){return Math.round(4000*econScale());}
  function feedBank(a){pig=Math.min(pigCap(),pig+Math.round(a*0.25));}
  function gainCoins(base){let m=payMult();if(activePet==='mole')m*=1+0.15*petPow();const w=Math.round(base*m);coins+=w;feedBank(w);return w;}
  function awardCoins(n){coins+=n;feedBank(n);return n;}
  function pickRival(){return RIVALS[Math.floor(Math.random()*RIVALS.length)];}
  function todayStr(){return new Date().toDateString();}
  function yesterdayStr(){const d=new Date();d.setDate(d.getDate()-1);return d.toDateString();}
  function dailyAvailable(){return lastClaim!==todayStr();}
  function maxBetIdx(){return Math.min(world+1,BET_LEVELS.length-1);}
  function bet(){betIdx=Math.min(betIdx,maxBetIdx());return BET_LEVELS[betIdx];}
  function setCompletable(s){return setActive(s)&&!setsDone[s.key]&&cardEmojis(s).every(function(r){return (relicsOwned[r]||0)>=1;});}
  function trimZ(x){let s=x.toFixed(2);while(s.indexOf('.')>=0&&(s.charAt(s.length-1)==='0'||s.charAt(s.length-1)==='.'))s=s.substring(0,s.length-1);return s;}
  function fmt(n){n=Math.round(n);const a=Math.abs(n);if(a<1e5)return n.toLocaleString();const u=['K','M','B','T','Qa','Qi','Sx','Sp','Oc','No','Dc'];let v=a,i=-1;while(v>=1000&&i<u.length-1){v/=1000;i++;}if(v>=1000)return n.toExponential(2);return (n<0?'-':'')+trimZ(v)+u[i];}
  function rating(){return world*40+totBuild*3+Object.keys(setsDone).length*40+Object.keys(goldSetsDone).length*60+petsOwned.length*15;}
  function regenSpins(){const CAP=SPIN_CAP;if(spins>=CAP){regenAnchor=Date.now();return;}const elapsed=Date.now()-regenAnchor;const periods=Math.floor(elapsed/SPIN_REGEN_MS);if(periods>0){spins=Math.min(CAP,spins+periods);regenAnchor+=periods*SPIN_REGEN_MS;if(spins>=CAP)regenAnchor=Date.now();}}

  function worldRule(){return WORLD_DATA[world%WORLD_DATA.length];}
  function rs(n){if(!rivalState[n])rivalState[n]={g:0,hp:25};return rivalState[n];}
  function recomputeNemesis(){let best=null,bg=NEM_THRESH-1;RIVALS.forEach(r=>{const s=rs(r.n);if(s.g>bg){bg=s.g;best=r.n;}});nemesisId=best;}
  function nemesisRival(){return nemesisId?RIVALS.find(r=>r.n===nemesisId):null;}
  function addGrudge(n,amt){const s=rs(n);s.g=Math.max(0,s.g+amt);recomputeNemesis();}
  function duelStage(g){return g>=10?3:(g>=7?2:1);}
  function duelName(st){return st>=3?'Showdown':(st>=2?'Feud':'Grudge');}
  function defCount(k){return defense.filter(d=>d===k).length;}
  function snareBlocks(){const c=defCount('snare');return c>0&&Math.random()<(0.22*c);}
  function applyBarricade(loss){const c=defCount('barricade');return c>0?Math.round(loss*Math.pow(0.75,c)):loss;}
  function watchCounter(loss){const c=defCount('watch');return (c>0&&Math.random()<(0.25*c))?Math.round(loss*0.5):0;}
  function emptySlot(){return defense.indexOf(null);}

  function dayNum(){return Math.floor(Date.now()/EVT_DUR);}
  function dayEnd(d){return (d+1)*EVT_DUR;}
  function scheduledKeys(d){const keys=['treasure'];keys.push(d%2===0?'attackMad':'raidMad');if(d%3===0)keys.push('cardsBoom');if(d%4===0)keys.push('villageMania');if(d%7===0)keys.push('vikingQuest');return keys;}
  function syncEvents(){const d=dayNum(),want=scheduledKeys(d);let changed=false;
    activeEvents=activeEvents.filter(e=>want.indexOf(e.key)>=0&&e.day===d);
    want.forEach(k=>{if(!activeEvents.find(e=>e.key===k)){const t=EVENT_TYPES[k];activeEvents.push({key:k,day:d,end:dayEnd(d),progress:0,claimed:t.rungs?t.rungs.map(()=>false):[]});changed=true;}});
    if(changed)save();}
  function evtActive(k){return !!activeEvents.find(e=>e.key===k);}
  function chestMult(){return evtActive('cardsBoom')?1.5:1;}
  function buildMult(){return evtActive('villageMania')?0.5:1;}
  function addEvtProgress(metric,amt){activeEvents.forEach(e=>{const t=EVENT_TYPES[e.key];if(t.kind==='progress'&&t.metric===metric)e.progress+=amt;});}
  function evtClaimable(e){const t=EVENT_TYPES[e.key];return t.rungs&&t.rungs.some((r,i)=>e.progress>=r.at&&!e.claimed[i]);}
  function anyEvtClaimable(){return activeEvents.some(evtClaimable);}

  function petPow(){var lv=activePet?(petLvl[activePet]||1):1;return (petAwakeActive()?1:0.4)*(1+0.08*(lv-1))*(specialWorld?1.2:1);}
  function petAwakeActive(){return petAwake>Date.now();}
  function grantTreat(n){treats+=n;}
  function feedPet(){if(treats<=0||!activePet)return;treats--;petAwake=Math.max(petAwake,Date.now())+4*3600*1000;var k=activePet;petXP[k]=(petXP[k]||0)+1;var need=(petLvl[k]||1)*5;if(petXP[k]>=need){petXP[k]=0;petLvl[k]=(petLvl[k]||1)+1;sBig();confetti(16);popup(PETS[k].icon,PETS[k].name+' — Level '+petLvl[k]+'!','Its bonus is stronger now.');}else{sPop();}renderPets();save();render();}

  function grantJoker(n){for(let i=0;i<n;i++)jokers.push({exp:Date.now()+JOKER_TTL});}
  function pruneJokers(){const before=jokers.length;jokers=jokers.filter(j=>j.exp>Date.now());if(jokers.length!==before)save();}
  function grantGold(n){for(let i=0;i<n;i++){const r=RELIC_POOL[Math.floor(Math.random()*RELIC_POOL.length)][0];goldOwned[r]=(goldOwned[r]||0)+1;}}
  function goldComplete(s){return setActive(s)&&!goldSetsDone[s.key]&&cardEmojis(s).every(function(r){return (goldOwned[r]||0)>=1;});}
  function useJokerOn(r){if(jokers.length<=0)return;jokers.shift();relicsOwned[r]=(relicsOwned[r]||0)+1;jokerChoosing=false;sBig();coinRain(8);popup('🃏','Joker Used!','Created relic '+r+'. Complete the set to claim its reward!');renderRelics();save();render();}

  let actx=null;
  function audio(){if(!actx){try{actx=new (window.AudioContext||window.webkitAudioContext)();}catch(e){}}if(actx&&actx.state==='suspended')actx.resume();return actx;}
  function beep(f,dur,type,vol,when){if(muted)return;const a=audio();if(!a)return;const o=a.createOscillator(),g=a.createGain();o.type=type||'sine';o.frequency.value=f;o.connect(g);g.connect(a.destination);const t=a.currentTime+(when||0);g.gain.setValueAtTime(0,t);g.gain.linearRampToValueAtTime(vol||0.14,t+0.01);g.gain.exponentialRampToValueAtTime(0.001,t+dur);o.start(t);o.stop(t+dur);}
  function _noise(dur){const a=audio();if(!a)return null;const len=Math.max(1,Math.floor(a.sampleRate*dur));const buf=a.createBuffer(1,len,a.sampleRate);const d=buf.getChannelData(0);for(let i=0;i<len;i++)d[i]=Math.random()*2-1;const s=a.createBufferSource();s.buffer=buf;return s;}
  function _tone(f,dur,type,vol,when,end){if(muted)return;const a=audio();if(!a)return;const o=a.createOscillator(),g=a.createGain();o.type=type;o.frequency.setValueAtTime(f,a.currentTime+(when||0));if(end)o.frequency.exponentialRampToValueAtTime(end,a.currentTime+(when||0)+dur);o.connect(g);g.connect(a.destination);const t=a.currentTime+(when||0);g.gain.setValueAtTime(0.0008,t);g.gain.exponentialRampToValueAtTime(vol,t+0.01);g.gain.exponentialRampToValueAtTime(0.0008,t+dur);o.start(t);o.stop(t+dur+0.03);}
  function _click(when,vol,f){if(muted)return;const a=audio();if(!a)return;const s=_noise(0.04);if(!s)return;const g=a.createGain(),bp=a.createBiquadFilter();bp.type='bandpass';bp.frequency.value=f||1600;bp.Q.value=1.4;s.connect(bp);bp.connect(g);g.connect(a.destination);const t=a.currentTime+(when||0);g.gain.setValueAtTime(vol||0.18,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.04);s.start(t);s.stop(t+0.06);}
  var SCALES={maj:[0,2,4,5,7,9,11,12],pent:[0,2,4,7,9,12,14,16],min:[0,2,3,5,7,8,10,12],pdom:[0,1,4,5,7,8,10,12],whole:[0,2,4,6,8,10,12,14],lyd:[0,2,4,6,7,9,11,12]};
  var SOUND_THEMES={forest:{root:440,scale:'pent',osc:'triangle',sub:'sine',sp0:300,sp1:540,coinT:'triangle',stopF:150,clickF:900,br:0.9},water:{root:523,scale:'pent',osc:'sine',sub:'sine',sp0:360,sp1:760,coinT:'sine',stopF:240,clickF:1500,br:1.2},cave:{root:330,scale:'min',osc:'triangle',sub:'sine',sp0:180,sp1:360,coinT:'sine',stopF:110,clickF:600,br:0.8},city:{root:494,scale:'maj',osc:'square',sub:'sawtooth',sp0:320,sp1:660,coinT:'square',stopF:200,clickF:1700,br:1.0},desert:{root:466,scale:'pdom',osc:'sawtooth',sub:'triangle',sp0:280,sp1:520,coinT:'triangle',stopF:170,clickF:1100,br:0.95},snow:{root:659,scale:'maj',osc:'sine',sub:'triangle',sp0:440,sp1:900,coinT:'sine',stopF:300,clickF:2300,br:1.3},space:{root:392,scale:'whole',osc:'sawtooth',sub:'square',sp0:200,sp1:920,coinT:'square',stopF:140,clickF:1800,br:1.1},myth:{root:523,scale:'lyd',osc:'sawtooth',sub:'triangle',sp0:330,sp1:680,coinT:'triangle',stopF:160,clickF:1300,br:1.05}};
  function ST(){return SOUND_THEMES[worldRule().set]||SOUND_THEMES.forest;}
  function sc(){var th=ST(),sm=SCALES[th.scale]||SCALES.maj;return sm.map(function(x){return th.root*Math.pow(2,x/12);});}
  function sSpin(){if(muted)return;var TH=ST();_tone(TH.sp0,0.5,'triangle',0.05,0,TH.sp1);_tone(TH.sp0/2,0.42,TH.sub,0.03,0.04,TH.sp1/2);}
  function sStop(){var TH=ST();_click(0,0.2,TH.clickF);_tone(TH.stopF,0.13,'sine',0.2,0,TH.stopF*0.46);}
  function sTick(){_click(0,0.12,2200);}
  function sWin(){var TH=ST(),f=sc();[f[2],f[4],f[6]].forEach((x,i)=>_tone(x,0.34,TH.osc,0.16,i*0.07));[f[4],f[5],f[6],f[7]].forEach((x,i)=>_tone(x*1.5,0.5,'sine',0.06*TH.br,0.18+i*0.05));}
  function sBig(){var TH=ST(),f=sc();[f[0],f[2],f[4],f[5],f[6],f[7]].forEach((x,i)=>_tone(x,0.4,TH.osc,0.14,i*0.075));[f[5],f[6],f[7]].forEach((x,i)=>_tone(x*2,0.6,'sine',0.08*TH.br,0.3+i*0.045));}
  function sCoin(){var TH=ST();for(let i=0;i<6;i++){const t=i*0.06;_tone(1250+Math.random()*450,0.08,TH.coinT,0.08,t);_tone(2500+Math.random()*500,0.06,'sine',0.05,t+0.012);}}
  function sHit(){_tone(120,0.36,'sawtooth',0.2,0,52);_click(0,0.24,300);}
  function sPop(){var TH=ST();_tone(TH.root,0.13,'triangle',0.12,0,TH.root*1.5);}
  function sTap(){_click(0,0.1,1500);}
  function sFanfare(){var TH=ST(),f=sc();[f[0],f[2],f[4],f[5],f[6],f[7],f[7]*2].forEach((x,i)=>_tone(x,0.3,TH.osc,0.14,i*0.08));[f[5],f[6],f[7]].forEach((x,i)=>_tone(x*1.5,0.7,'sine',0.1,0.5+i*0.05));}
  function haptic(p){if(typeof navigator!=='undefined'&&navigator.vibrate){try{navigator.vibrate(p);}catch(e){}}}

  function coinRain(n){const c=$('rain');for(let i=0;i<n;i++){const d=document.createElement('div');d.className='c';d.textContent='🪙';d.style.left=Math.random()*100+'%';d.style.animationDelay=(Math.random()*0.4)+'s';d.style.fontSize=(18+Math.random()*18)+'px';c.appendChild(d);setTimeout(()=>d.remove(),1700);}}
  function confetti(n){const c=$('rain');const ps=['🎉','✨','🎊','⭐','🎈','💫'];for(let i=0;i<n;i++){const d=document.createElement('div');d.className='c';d.textContent=ps[Math.floor(Math.random()*ps.length)];d.style.left=Math.random()*100+'%';d.style.animationDelay=(Math.random()*0.5)+'s';d.style.fontSize=(15+Math.random()*16)+'px';c.appendChild(d);setTimeout(()=>d.remove(),1900);}}
  var _baTO=[],_baSpark=null;
  function playBuildAnim(idx){var items=worldItems();var it=items[idx];if(!it)return;
    var host=$('buildAnim');if(!host){host=document.createElement('div');host.id='buildAnim';host.className='banim';document.body.appendChild(host);}
    host.className='banim';
    host.innerHTML='<div class="bp-scene"><div class="bp-piece"><span class="bp-emoji">'+it.i+'</span></div><div class="bp-cloud"><div class="bp-puff p1"></div><div class="bp-puff p2"></div><div class="bp-puff p3"></div><div class="bp-puff p4"></div><div class="bp-puff p5"></div><div class="bp-gear">⚙️</div><div class="bp-hammer">🔨</div><div class="bp-saw">🪚</div></div></div><div class="bp-title">Building '+it.n+'...</div><div class="bp-sub">Hammering it up to 5 stars!</div><div class="bp-stars" id="baStars"></div><button class="bp-skip" id="baSkip">Tap to continue</button>';
    var pw=host.querySelector('.bp-piece');if(pw){var rg=world%WORLD_ITEMS.length;var im=document.createElement('img');im.className='bp-img';im.alt='';im.onload=function(){pw.classList.add('hasimg');};im.onerror=function(){im.remove();};im.src=pieceSrc(rg,idx);pw.appendChild(im);}
    _baTO.forEach(clearTimeout);_baTO=[];if(_baSpark){clearInterval(_baSpark);_baSpark=null;}
    requestAnimationFrame(function(){host.classList.add('show');});
    sBig();haptic(12);
    var cloud=host.querySelector('.bp-cloud');
    _baSpark=setInterval(function(){if(!cloud)return;for(var i=0;i<3;i++){(function(){var sp=document.createElement('div');sp.className='bp-spark';var ang=Math.random()*6.283,dist=28+Math.random()*44;sp.style.setProperty('--dx',(Math.cos(ang)*dist).toFixed(1)+'px');sp.style.setProperty('--dy',(Math.sin(ang)*dist-12).toFixed(1)+'px');sp.style.background=Math.random()<0.5?'#ffd86b':'#e6c49a';sp.style.animation='bpSparkFly .5s ease-out forwards';cloud.appendChild(sp);setTimeout(function(){sp.remove();},520);})();}},340);
    _baTO.push(setTimeout(function(){if(_baSpark){clearInterval(_baSpark);_baSpark=null;}host.classList.add('done');var t=host.querySelector('.bp-title');if(t)t.textContent=it.n+' Complete!';var st=$('baStars');if(st)st.innerHTML='';for(var s=0;s<5;s++){(function(k){_baTO.push(setTimeout(function(){var b=document.createElement('b');b.textContent='★';var sr=$('baStars');if(sr)sr.appendChild(b);sPop();},k*200));})(s);}confetti(30);coinRain(8);haptic(30);},6200));
    _baTO.push(setTimeout(closeBuildAnim,12500));
    var sk=$('baSkip');if(sk)sk.onclick=closeBuildAnim;
    host.onclick=function(){if(host.classList.contains('done'))closeBuildAnim();};}
  function closeBuildAnim(){var host=$('buildAnim');if(!host)return;_baTO.forEach(clearTimeout);_baTO=[];if(_baSpark){clearInterval(_baSpark);_baSpark=null;}host.classList.remove('show');setTimeout(function(){if(host)host.classList.remove('done');},400);}
  const HUB_ITEMS=[{i:'📖',l:'How to Play',m:'faqModal'},{i:'🏗️',l:'Village',m:'villageModal',f:'renderVillageShop'},{i:'🎁',l:'Daily',m:'dailyModal',f:'renderDaily',k:'daily'},{i:'📅',l:'Events',m:'eventModal',f:'renderEvents',k:'event'},{i:'🃏',l:'Cards',m:'relicModal',f:'renderRelics',k:'relic'},{i:'🐾',l:'Pets',m:'petModal',f:'renderPets',k:'pet'},{i:'👥',l:'Rivals',m:'rosterModal',f:'renderRoster',k:'roster'},{i:'🧱',l:'Defenses',m:'defModal',f:'renderDef',k:'def'},{i:'📺',l:'Free Spins',m:'adModal',f:'renderAds',k:'ad'},{i:'🎰',l:'Spin Shop',m:'shopModal',f:'renderShop'},{i:'💎',l:'Gems',m:'gemModal',f:'renderGems'},{i:'🗺️',l:'Map',m:'mapModal',f:'renderMap'},{i:'🎡',l:'Wheel',m:'wheelModal',f:'renderWheel',k:'wheel'},{i:'🏆',l:'Leaderboard',soon:1},{i:'👫',l:'Friends',soon:1},{i:'📰',l:'News',soon:1}];
