    const cw=$('chargeWrap');if(cw){const fr=frenzy>0;cw.classList.toggle('frenzy',fr);$('chargeFill').style.width=(fr?100:Math.min(100,charge))+'%';$('chargeTxt').textContent=fr?('🔥 FRENZY ×'+frenzy):'⚡ Charge';}
