  var PIECE_DATA={'r0_0':'data:image/webp;base64,','r0_1':'data:image/webp;base64,','r0_2':'data:image/webp;base64,','r0_3':'data:image/webp;base64,','r0_4':'data:image/webp;base64,','r1_0':'data:image/webp;base64,','r1_1':'data:image/webp;base64,','r1_2':'data:image/webp;base64,','r1_3':'data:image/webp;base64,','r1_4':'data:image/webp;base64,','r2_0':'data:image/webp;base64,','r2_1':'data:image/webp;base64,','r2_2':'data:image/webp;base64,','r2_3':'data:image/webp;base64,','r2_4':'data:image/webp;base64,','r3_0':'data:image/webp;base64,','r3_1':'data:image/webp;base64,','r3_2':'data:image/webp;base64,','r3_3':'data:image/webp;base64,','r3_4':'data:image/webp;base64,','r4_0':'data:image/webp;base64,','r4_1':'data:image/webp;base64,','r4_2':'data:image/webp;base64,','r4_3':'data:image/webp;base64,','r4_4':'data:image/webp;base64,'};
